var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라? 내가 교실을 잘못 들어왔나?","JPN":"あれ？　あたし、教室を間違えたのかな？","ENG":"Oh? Did I walk into the wrong classroom?","TWN":"嗯？我是不是走錯教室了？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"잘못 들어오지 않았소. 눈앞에 보이는 건 분명 나이엘이오.","JPN":"間違えていません。目の前にいるのは確かにナイエルです。","ENG":"You did not. The person in front of you is, without a doubt, Naielle.","TWN":"在下沒走錯，眼前的確是奈爾。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"지금까지 봉사활동을 해오면서 마음을 다잡은 것일지도 모르겠구려.","JPN":"これまでのボランティア活動で、心を入れ替えたのかもしれませんね。","ENG":"Perhaps all the volunteering has calmed her mind.","TWN":"難道是志工活動改變她的嗎？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"웬일이야? 네가 오리엔테이션부터 수업을 들으러 오다니.","JPN":"あなたがオリエンテーションから授業に参加するなんて、どうしたの？","ENG":"What are you doing here? I can't believe you came to class orientation.","TWN":"什麼風把你吹來了？你居然從新學期說明會就開始就來上課了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 그 낙하산이 얼마나 대단한 사람인지 시험하러 온 것뿐이야.","JPN":"ふん。あのコネ教師がどれほどすごい人なのか、試しに来ただけよ。","ENG":"Hmph. I'm just here to test the teacher who got in through favoritism.","TWN":"哼，我只是來試試那個空降部隊到底有多厲害。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"기준 미달인 사람이 감히 선생이랍시고……\xA0\xA0","JPN":"基準以下のくせに先生を名乗るなんて……\xA0\xA0","ENG":"How dare this unqualified person try to–\xA0\xA0","TWN":"不合格的人竟敢自稱老師……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우왓, 깜짝이야! 언제부터 옆에 있던 거야?!","JPN":"わっ、びっくりした！　いつからそこにいたのよ！","ENG":"WHOA!! How long have you been there?!","TWN":"哇，嚇我一跳！你什麼時候來的？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시험하러 온 것뿐이야…… 부터?","JPN":"試しに来ただけよ……から？","ENG":"Since when you were talking about testing... me?","TWN":"測試你一下……什麼叫從哪來？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그럼 처음부터 있었던 거잖아……!","JPN":"じゃ、じゃあ最初からいたんじゃない……！","ENG":"Th-then you were there from the start...!","TWN":"剛，剛才不是在那嗎……！"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"전혀 눈치채지 못했어! 어떻게 한 거지?","JPN":"全然気づけなかった……！　どうして？","ENG":"I didn't even notice her! How did she do that?","TWN":"完全沒有察覺到！你是怎麼做到的？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"자리에 앉아 줄래……?","JPN":"席に座ってくれる……？","ENG":"Could you all take your seats...?","TWN":"能坐下嗎……？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시작했으니까……. 수업.","JPN":"始まったから……授業。","ENG":"The class has... already started.","TWN":"開始……上課。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"모두 안녕……. 진보라라고 해…….","JPN":"こんにちは……先生の名前はタカダ・シホ……","ENG":"Hello, everyone... I am Jin Bora...","TWN":"你們好……我叫陳寶拉……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시뮬레이션…… 모의전투 강사를 담당했어.","JPN":"シミュレーション……模擬戦闘の講師を担当することになった。","ENG":"I am going to be your instructor... for the simulation.","TWN":"我是負責模擬戰鬥的講師。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"정식 수업은 내일부터니까…… 오늘은 간단하게.","JPN":"正式な授業は明日からなので……今日は簡単に。","ENG":"The class will start tomorrow, so... I'll make this one quick.","TWN":"正式課程從明天開始……今天就簡單一點。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"그럼 설명해 줄게…… 내일 수업에 대해.","JPN":"じゃあ、説明するよ……明日の授業のこと。","ENG":"Here's what you need to know... about tomorrow's class.","TWN":"那我來解釋一下……關於明天的課程。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시뮬레이션엔 새로운 모드가 도입될 거야…… 카운터즈 레거시.","JPN":"シミュレーションには、新しいモードが導入される……カウンターズ・レガシー。","ENG":"The simulation will have a new mode implemented... Counters Legacy.","TWN":"即將引入一個新的模擬模式……制裁者的遺產。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"지금까진 아카데미에서만 접속했었지……?","JPN":"今までは、アカデミーでしかアクセスしてなかったよね……？","ENG":"Only the Academy had access so far, right?","TWN":"到目前為止，你們一直是從學院登入的吧……？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"확장할 거야…… 서버……. 그라운드 원의 카운터들도 접속할 수 있게.","JPN":"拡張するんだよ……サーバー……グラウンド・ワンのカウンターもアクセスできるように。","ENG":"We are expanding... the server... so Counters from Ground One can also access it.","TWN":"會擴展……伺服器……讓G1制裁者們也能連接得上。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐, 일반인들도 접속할 수 있다고?","JPN":"それって、一般人もアクセスできるってこと？","ENG":"Wait, normal people can also access it?","TWN":"等等，普通人也能登入嗎？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"시뮬레이션 서버는 관리국과 아카데미에서만 접속 가능한 거로 알고 있는데?","JPN":"シミュレーションサーバーは管理局とアカデミーでしかアクセスできないはずよ。","ENG":"As I know, the simulation server was only accessible at the Administration and the Academy.","TWN":"我知道模擬伺服器只能從管理局和學院連線？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"서버는 분리할 거야…… 3개로.","JPN":"サーバーは分離する……3つに。","ENG":"The server will be split... into three.","TWN":"伺服器將會分成……3個。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"아카데미, 그라운드 원, 그리고…… 모두가 만날 수 있는 서버.","JPN":"アカデミー、グラウンド・ワン、そして……誰でも入場できるサーバー。","ENG":"Academy, Ground One, and... a server where everyone can meet.","TWN":"學院、G1，以及……所有人都能登入的伺服器。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"하지만…… 당분간 아카데미 서버만 이용 가능해.","JPN":"でも……しばらく、利用できるのはアカデミーサーバーだけ。","ENG":"But... only the Academy server will be available for the time being.","TWN":"但是……目前只能使用學院伺服器。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시뮬레이션이니까 다칠 위험도 없고…… 좋은 훈련이 될 거야.","JPN":"シミュレーションだから怪我する恐れもない……きっといい訓練になる。","ENG":"Because it's a simulation, there is no risk of getting injured... and it will be good training.","TWN":"因為是模擬訓練，所以沒有受傷的風險……是個不錯的訓練模式。"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};